//! AMM engine integration tests — create, deposit, withdraw, vote, bid.
//!
//! Ported from C++ AMM_test.cpp (608 assertions).

use super::fixtures::*;
use super::pipeline::full_apply;
use app::state::transactor_dispatcher::handle_real_dispatch;
use basics::base_uint::{Uint160, Uint256};
use ledger::{ApplyView, ReadView};
use protocol::{
    AccountID, Currency, IOUAmount, Issue, STAmount, STArray, STLedgerEntry, STObject, STTx, Ter,
    TxType, XRPAmount, get_field_by_symbol, sf_generic,
};
use std::sync::Arc;

fn sf(name: &str) -> &'static protocol::SField {
    get_field_by_symbol(name)
}

// ─── AMM Create ─────────────────────────────────────────────────────────────

#[test]
fn amm_create_xrp_usd() {
    let a = acct(0x11);
    let gw = acct(0x33);
    let l = build_ledger_with_features(
        vec![
            account_root(a, 50_000_000_000, 1, 0),
            account_root(gw, 50_000_000_000, 0, 0x00800000),
            trust_line(a, gw, usd_currency(), 100000, 1000000, 0),
        ],
        vec!["AMM"],
    );
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(5_000_000_000));
        tx.set_field_amount(sf("sfAmount2"), iou(gw, usd_currency(), 5000));
        tx.set_field_u16(sf("sfTradingFee"), 100);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    assert_eq!(
        full_apply(&mut v, &tx, TxType::AMM_CREATE),
        Ter::TES_SUCCESS
    );
}
