// ─── Credential: 10 Different Types ────────────────────────────────────────

#[test]
fn amm7_credential_10_types() {
    let i = acct(0x11);
    let s = acct(0x22);
    let l = build_ledger(vec![
        account_root(i, 10_000_000_000, 0, 0),
        account_root(s, 5_000_000_000, 0, 0),
    ]);
    let mut v = new_view(l);
    for (seq, ctype) in (1..=10u32).zip(
        [
            "KYC",
            "AML",
            "ACCREDITED",
            "QUALIFIED",
            "PROFESSIONAL",
            "INSTITUTIONAL",
            "RETAIL",
            "WHOLESALE",
            "PREMIUM",
            "STANDARD",
        ]
        .iter(),
    ) {
        let tx = STTx::new(TxType::CREDENTIAL_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), i);
            tx.set_account_id(sf("sfSubject"), s);
            tx.set_field_vl(sf("sfCredentialType"), ctype.as_bytes());
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), seq);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx, TxType::CREDENTIAL_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
}

