// ─── Vault: 100 Owners With Various Currencies ──────────────────────────────

#[test]
fn amm24_vault_100_currencies() {
    for (i, c) in (0x41u8..=0x72).zip(
        [
            "USD", "EUR", "GBP", "JPY", "CHF", "CAD", "AUD", "NZD", "CNY", "INR", "KRW", "SGD",
            "HKD", "MXN", "BRL", "ZAR", "SEK", "NOK", "DKK", "PLN", "CZK", "HUF", "RON", "BGN",
            "HRK", "ISK", "RUB", "TRY", "THB", "TWD", "PHP", "IDR", "MYR", "VND", "ARS", "CLP",
            "COP", "PEN", "UYU", "BOB", "PYG", "GHS", "KES", "NGN", "EGP", "MAD", "TND", "ZMW",
            "UGX", "TZS",
        ]
        .iter(),
    ) {
        let o = acct(i);
        let gw = acct(0x33);
        let cur = protocol::currency_from_string(c);
        let l = build_ledger_with_features(
            vec![
                account_root(o, 10_000_000_000, 0, 0),
                account_root(gw, 10_000_000_000, 0, 0x00800000),
            ],
            vec!["SingleAssetVault", "MPTokensV1", "PermissionedDomains"],
        );
        let mut v = new_view(l);
        let tx = STTx::new(TxType::VAULT_CREATE, |tx| {
            tx.set_account_id(sf("sfAccount"), o);
            tx.set_field_amount(sf("sfAsset"), iou(gw, cur, 0));
            tx.set_field_amount(sf("sfFee"), xrp(10));
            tx.set_field_u32(sf("sfSequence"), 1);
        });
        assert_eq!(
            handle_real_dispatch(&mut v, &tx, TxType::VAULT_CREATE, None),
            Ter::TES_SUCCESS
        );
    }
}

