/// C++: AMM with both XRP tokens -> temBAD_AMM_TOKENS
#[test]
fn cpp_amm_create_both_xrp() {
    let a = acct(0x41);
    let l = build_ledger(vec![account_root(a, 50_000_000_000, 0, 0)]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(10_000_000_000));
        tx.set_field_amount(sf("sfAmount2"), xrp(10_000_000_000));
        tx.set_field_u16(sf("sfTradingFee"), 0);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = full_apply(&mut v, &tx, TxType::AMM_CREATE);
    assert_eq!(r, Ter::TEM_BAD_AMM_TOKENS);
}

/// C++: AMM with zero amount -> temBAD_AMOUNT
#[test]
fn cpp_amm_create_zero_amount() {
    let a = acct(0x41);
    let gw = acct(0x33);
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 1, 0),
        account_root(gw, 50_000_000_000, 0, 0),
        trust_line(a, gw, usd_currency(), 30000, 50000, 0),
    ]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(0));
        tx.set_field_amount(sf("sfAmount2"), iou(gw, usd_currency(), 10000));
        tx.set_field_u16(sf("sfTradingFee"), 0);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = full_apply(&mut v, &tx, TxType::AMM_CREATE);
    assert_eq!(r, Ter::TEM_BAD_AMOUNT);
}

/// C++: AMM with negative amount -> temBAD_AMOUNT
#[test]
fn cpp_amm_create_negative_amount() {
    let a = acct(0x41);
    let gw = acct(0x33);
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 1, 0),
        account_root(gw, 50_000_000_000, 0, 0),
        trust_line(a, gw, usd_currency(), 30000, 50000, 0),
    ]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), STAmount::new_native(10_000_000_000, true));
        tx.set_field_amount(sf("sfAmount2"), iou(gw, usd_currency(), 10000));
        tx.set_field_u16(sf("sfTradingFee"), 0);
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = full_apply(&mut v, &tx, TxType::AMM_CREATE);
    assert_eq!(r, Ter::TEM_BAD_AMOUNT);
}

/// C++: AMM with invalid trading fee (>1000 = 1%) -> temBAD_FEE
#[test]
fn cpp_amm_create_invalid_trading_fee() {
    let a = acct(0x41);
    let gw = acct(0x33);
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 1, 0),
        account_root(gw, 50_000_000_000, 0, 0),
        trust_line(a, gw, usd_currency(), 30000, 50000, 0),
    ]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_CREATE, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(10_000_000_000));
        tx.set_field_amount(sf("sfAmount2"), iou(gw, usd_currency(), 10000));
        tx.set_field_u16(sf("sfTradingFee"), 65001); // > max 65000
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = full_apply(&mut v, &tx, TxType::AMM_CREATE);
    assert_eq!(r, Ter::TEM_BAD_FEE);
}

