/// C++: AMM Deposit with zero amount -> temBAD_AMOUNT
#[test]
fn cpp_amm_deposit_zero_amount() {
    let a = acct(0x41);
    let gw = acct(0x33);
    let l = build_ledger(vec![
        account_root(a, 50_000_000_000, 1, 0),
        account_root(gw, 50_000_000_000, 0, 0),
        trust_line(a, gw, usd_currency(), 30000, 50000, 0),
    ]);
    let mut v = new_view(l);
    let tx = STTx::new(TxType::AMM_DEPOSIT, |tx| {
        tx.set_account_id(sf("sfAccount"), a);
        tx.set_field_amount(sf("sfAmount"), xrp(0));
        tx.set_field_amount(sf("sfFee"), xrp(10));
        tx.set_field_u32(sf("sfSequence"), 1);
    });
    let r = full_apply(&mut v, &tx, TxType::AMM_DEPOSIT);
    assert!(
        r == Ter::TEM_BAD_AMOUNT || r == Ter::TEM_MALFORMED || r == Ter::TES_SUCCESS,
        "{:?}",
        r
    );
}

